import React from 'react';
import './VisitorMap.css';

const VisitorMap = () => {
  return (
    <div className="visitor-map">
      <a href="https://clustrmaps.com/site/1c9dh" title="ClustrMaps">
        <img
          src="https://www.clustrmaps.com/map_v2.png?d=1-apcJaW_PAd_0Sw4pQw2NOQ05EYEunPmJO7dTTtkn0&cl=ffffff"
          alt="Visitor Map"
        />
      </a>
    </div>
  );
};

export default VisitorMap;
